    class UserService {
      private users: Map<string, User>;

      // 输入 "constructor() {" 后，AI 可能建议：
      // constructor() {
      //   this.users = new Map();
      // }

      // 输入 "addUser(user: User): " 后，AI 会建议返回类型和完整方法体
      addUser(user: User): boolean {
        // AI 补全建议：
        if (this.users.has(user.id)) {
          return false;
        }
        this.users.set(user.id, user);
        return true;
      }

      // 输入 "async fetchUsers(" 后，AI 会补全参数和完整异步方法
      async fetchUsers(filter?: UserFilter): Promise<User[]> {
        // AI 补全：
        const allUsers = Array.from(this.users.values());
        if (!filter) return allUsers;

        return allUsers.filter(user => {
          if (filter.role && user.role !== filter.role) return false;
          if (filter.active !== undefined && user.active !== filter.active) return false;
          return true;
        });
      }
