    def exists_by_username(self, username: str) -> bool:
        """检查用户名是否已存在"""
        result = self.db.query(
            'SELECT 1 FROM users WHERE username = ? LIMIT 1',
            (username,)
        )
        return result is not None

    def exists_by_email(self, email: str) -> bool:
        """检查邮箱是否已存在"""
        result = self.db.query(
            'SELECT 1 FROM users WHERE email = ? LIMIT 1',
            (email,)
        )
        return result is not None

    def create(self, username: str, email: str, password_hash: str) -> int:
        """创建新用户"""
        return self.db.insert(
            'INSERT INTO users (username, email, password_hash, created_at) VALUES (?, ?, ?, NOW())',
            (username, email, password_hash)
        )

class PasswordHasher:
    """密码哈希服务"""

    def hash(self, password: str) -> str:
        """对密码进行哈希处理"""
        return hashlib.sha256(password.encode()).hexdigest()

class EmailService:
    """邮件服务"""

    def __init__(self, email_sender):
        self.sender = email_sender

    def send_welcome_email(self, email: str, username: str) -> None:
        """发送欢迎邮件"""
        self.sender.send(
            to=email,
            subject='Welcome!',
            body=f'Hello {username}! Thank you for registering.'
        )

class Logger:
    """日志服务"""

    def info(self, message: str, **kwargs) -> None:
        """记录信息日志"""
        extra = ' '.join(f'{k}={v}' for k, v in kwargs.items())
        print(f'[INFO] {message} {extra}'.strip())

class UserRegistrationService:
    """
    用户注册服务 - 重构后的版本
    协调各个组件完成注册流程
    """

    def __init__(
        self,
        db,
        email_sender,
        settings_manager
    ):
        # 初始化各个验证器
        self.username_validator = UsernameValidator()
        self.email_validator = EmailValidator()
        self.password_validator = PasswordValidator()

        # 初始化仓储和服务
        self.user_repository = UserRepository(db)
        self.password_hasher = PasswordHasher()
        self.email_service = EmailService(email_sender)
        self.settings_manager = settings_manager
        self.logger = Logger()

    def register(self, request: UserRegistrationRequest) -> User:
        """
        执行用户注册流程

        Args:
            request: 注册请求数据

        Returns:
            User: 创建的用户对象

        Raises:
            ValidationError: 验证失败时抛出
        """
        # 1. 验证输入数据
        self._validate_request(request)

        # 2. 检查唯一性
        self._check_uniqueness(request)

        # 3. 创建用户
        user = self._create_user(request)

        # 4. 发送欢迎邮件
        self.email_service.send_welcome_email(request.email, request.username)

        # 5. 创建默认设置
        self.settings_manager.create_default(user.id)

        # 6. 记录日志
        self.logger.info(
            'User registered successfully',
            user_id=user.id,
            username=request.username
        )

        return user

    def _validate_request(self, request: UserRegistrationRequest) -> None:
        """验证注册请求"""
        self.username_validator.validate(request.username)
        self.email_validator.validate(request.email)
        self.password_validator.validate(request.password)

    def _check_uniqueness(self, request: UserRegistrationRequest) -> None:
        """检查用户名和邮箱唯一性"""
        if self.user_repository.exists_by_username(request.username):
            raise ValidationError('Username already exists')
        if self.user_repository.exists_by_email(request.email):
            raise ValidationError('Email already exists')

    def _create_user(self, request: UserRegistrationRequest) -> User:
        """创建用户记录"""
        password_hash = self.password_hasher.hash(request.password)
        user_id = self.user_repository.create(
            request.username,
            request.email,
            password_hash
        )
        return User(id=user_id, username=request.username, email=request.email)


