class UsernameValidator:
    """用户名验证器"""
    MIN_LENGTH = 3
    MAX_LENGTH = 20

    def validate(self, username: str) -> None:
        """验证用户名是否符合规范"""
        if not username:
            raise ValidationError('Username is required')
        if len(username) < self.MIN_LENGTH:
            raise ValidationError(f'Username must be at least {self.MIN_LENGTH} characters')
        if len(username) > self.MAX_LENGTH:
            raise ValidationError(f'Username must be at most {self.MAX_LENGTH} characters')
        if not re.match(r'^[a-zA-Z0-9_]+$', username):
            raise ValidationError('Username can only contain letters, numbers, and underscores')

class EmailValidator:
