```python
// 示例：使用 Composer 进行批量重构
// 将旧的颜色工具类迁移到新的实现

// 原始文件：utils/colorUtils.ts（旧实现）
// import { rgbToHex, hexToRgb, lighten, darken } from 'color-convert';
//
// export const color = {
//   toHex: (r: number, g: number, b: number) => rgbToHex(r, g, b),
//   toRgb: (hex: string) => hexToRgb(hex),
//   lighten: (hex: string, percent: number) => lighten(hex, percent),
//   darken: (hex: string, percent: number) => darken(hex, percent)
// };

// 使用 Composer 进行重构后的新实现：
// utils/colorUtils.ts（新实现）

/**
 * 颜色工具类
 * 提供 RGB 和十六进制颜色之间的转换功能
 * 使用原生实现，无需外部依赖
 */

export class ColorUtils {
  /**
   * RGB 转十六进制颜色
   */
  static toHex(r: number, g: number, b: number): string {
    const toHexComponent = (n: number): string => {
      const hex = Math.max(0, Math.min(255, Math.round(n))).toString(16);
      return hex.length === 1 ? '0' + hex : hex;
    };
    return `#${toHexComponent(r)}${toHexComponent(g)}${toHexComponent(b)}`;
  }

  /**
   * 十六进制转 RGB
   */
  static toRgb(hex: string): { r: number; g: number; b: number } {
    const cleanHex = hex.replace('#', '');
    const bigint = parseInt(cleanHex, 16);
    return {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255
    };
  }

  /**
   * 颜色变亮
   */
  static lighten(hex: string, percent: number): string {
    const { r, g, b } = this.toRgb(hex);
    const factor = 1 + percent / 100;
    return this.toHex(
      Math.min(255, r * factor),
      Math.min(255, g * factor),
      Math.min(255, b * factor)
    );
  }

  /**
   * 颜色变暗
   */
  static darken(hex: string, percent: number): string {
    const { r, g, b } = this.toRgb(hex);
    const factor = 1 - percent / 100;
    return this.toHex(
      r * factor,
      g * factor,
      b * factor
    );
  }
}

export const color = ColorUtils;

// 使用新工具的示例：components/Button.tsx

import { ColorUtils } from '../utils/colorUtils';

interface ButtonProps {
  baseColor?: string;
  variant?: 'primary' | 'secondary';
}

export const Button: React.FC<ButtonProps> = ({ 
  baseColor = '#007bff',
  variant = 'primary' 
}) => {
  // 使用 ColorUtils 获取变体颜色
  const backgroundColor = variant === 'primary' 
    ? baseColor 
    : ColorUtils.darken(baseColor, 20);

  const hoverColor = ColorUtils.lighten(baseColor, 10);

  return (
    <button
      style={{ 
        backgroundColor,
        color: '#fff',
        padding: '8px 16px',
        border: 'none',
        borderRadius: '4px',
        cursor: 'pointer',
        transition: 'background-color 0.2s'
      }}
      onMouseOver={(e) => e.currentTarget.style.backgroundColor = hoverColor}
    >
      点击我
    </button>
  );
};
```



## 常见错误

- 一次性描述过于复杂的功能，导致 AI 无法正确处理所有上下文信息
- 在描述任务时没有明确指定涉及的文件范围，导致修改范围过大或遗漏重要文件
- 忽略代码审查，直接使用 AI 生成的所有代码，可能引入安全隐患
- 在不同文件有依赖关系时，没有明确说明修改顺序，导致出现中间状态错误
- 使用模糊的描述如"实现类似功能"，而不是具体的实现要求
- 对于需要多次修改的复杂功能，试图在一次 Composer 操作中完成所有内容
- 没有检查 AI 生成代码的类型兼容性，导致 TypeScript 编译错误
- 忽略测试，导致重构后的代码没有适当的测试覆盖


## 最佳实践

- 将大型任务分解为多个小步骤，每次 Composer 操作专注于一个具体的目标
- 在描述任务时明确列出需要修改的文件，并说明它们之间的依赖关系
- 对于复杂的重构任务，先在小范围文件上测试，确认无误后再扩大范围
- 使用 TypeScript 的类型系统来帮助 AI 理解数据结构和接口要求
- 始终审查 AI 生成的代码，特别是涉及安全性的部分（如用户认证、数据验证）
- 在完成多文件修改后，运行项目的类型检查和测试来验证一致性
- 保持项目结构清晰规范，这有助于 AI 更准确地理解文件关系
- 对于核心业务逻辑，建议人工实现或至少进行详细审查，而不是完全依赖 AI 生成
- 定期保存重要的工作进度，避免意外丢失
- 使用 Git 等版本控制系统，方便追踪和回退 AI 造成的修改

