import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { UserDocument, AuthToken } from '../types/user';

export class AuthService {
  // 创建新用户
  async createUser(username: string, email: string, password: string): Promise<UserDocument> {
    const passwordHash = await bcrypt.hash(password, 10);
    // 这里应该是实际的数据库保存逻辑
    const user = { username, email, passwordHash, createdAt: new Date() };
    return user as UserDocument;
  }

  // 用户登录
  async login(email: string, password: string): Promise<AuthToken> {
    // 查找用户、验证密码的逻辑
    const token = jwt.sign({ userId: 'user._id' }, process.env.JWT_SECRET || 'secret', {
      expiresIn: '7d'
    });
    return {
      userId: 'user._id',
      token,
      expiresIn: 7 * 24 * 60 * 60 // 7天
    };
  }

  // Token 验证
  verifyToken(token: string): { userId: string } {
    return jwt.verify(token, process.env.JWT_SECRET || 'secret') as { userId: string };
  }
}

