/**
 * 颜色工具类
 * 提供 RGB 和十六进制颜色之间的转换功能
 * 使用原生实现，无需外部依赖
 */

export class ColorUtils {
  /**
   * RGB 转十六进制颜色
   */
  static toHex(r: number, g: number, b: number): string {
    const toHexComponent = (n: number): string => {
      const hex = Math.max(0, Math.min(255, Math.round(n))).toString(16);
      return hex.length === 1 ? '0' + hex : hex;
    };
    return `#${toHexComponent(r)}${toHexComponent(g)}${toHexComponent(b)}`;
  }

  /**
   * 十六进制转 RGB
   */
  static toRgb(hex: string): { r: number; g: number; b: number } {
    const cleanHex = hex.replace('#', '');
    const bigint = parseInt(cleanHex, 16);
    return {
      r: (bigint >> 16) & 255,
      g: (bigint >> 8) & 255,
      b: bigint & 255
    };
  }

  /**
   * 颜色变亮
   */
  static lighten(hex: string, percent: number): string {
    const { r, g, b } = this.toRgb(hex);
    const factor = 1 + percent / 100;
    return this.toHex(
      Math.min(255, r * factor),
      Math.min(255, g * factor),
      Math.min(255, b * factor)
    );
  }

  /**
   * 颜色变暗
   */
  static darken(hex: string, percent: number): string {
    const { r, g, b } = this.toRgb(hex);
    const factor = 1 - percent / 100;
    return this.toHex(
      r * factor,
      g * factor,
      b * factor
    );
  }
}

