service.addUser({
  id: 1,
  name: "张三",
  email: "zhangsan@example.com"
});

// 使用 AI 辅助诊断：尝试访问不存在的属性会报错
const user = service.getUser(1);
console.log(user.name.toUpperCase()); // 正常工作

// 模拟一个常见错误：undefined.toUpperCase()
const user2 = service.getUser(999);
// console.log(user2.name); // TypeError: Cannot read property 'name' of undefined

// AI 辅助修复建议：使用可选链
console.log(user2?.name?.toUpperCase() ?? 'Guest');


### 示例 2：Python 异常处理与 AI 辅助诊断

