import json
from typing import List, Dict, Any

class DataProcessor:
    """数据处理器类 - 展示 AI 辅助错误诊断"""

    def __init__(self):
        self.data: List[Dict[str, Any]] = []

    def load_data(self, file_path: str) -> bool:
        """
        加载数据文件
        AI 辅助：自动识别文件操作中的常见错误
        """
        try:
            with open(file_path, 'r', encoding='utf-8') as f:
                content = f.read()
                # 常见错误：JSON 解析失败未处理
                self.data = json.loads(content)
                return True
        except FileNotFoundError:
            print(f"错误：文件 {file_path} 不存在")
            return False
        except json.JSONDecodeError as e:
            print(f"错误：JSON 格式无效 - {e}")
            return False
        except UnicodeDecodeError:
            print("错误：文件编码不支持，请使用 UTF-8 编码")
            return False

    def process_data(self) -> Dict[str, Any]:
        """
        处理数据
        展示如何正确处理可能的空数据情况
        """
        if not self.data:
            # AI 辅助建议：提供明确的错误处理
            return {
                "status": "error",
                "message": "数据未加载，请先调用 load_data()"
            }

        # 正常处理逻辑
        result = {
            "status": "success",
            "count": len(self.data),
            "processed": [self._process_item(item) for item in self.data]
        }
        return result

    def _process_item(self, item: Dict[str, Any]) -> Dict[str, Any]:
        """
        处理单个数据项
        AI 辅助：类型检查和默认值处理
        """
        return {
            "id": item.get("id", 0),  # 使用 get 提供默认值
            "value": item.get("value", ""),
            "computed": self._compute_value(item)
        }

    def _compute_value(self, item: Dict[str, Any]) -> int:
        """
        计算值
        展示 AI 如何帮助识别潜在的运行时错误
        """
        try:
            # 常见错误：假设值存在或为数字
            base = int(item.get("base", 0))
            multiplier = item.get("multiplier", 1)
            return base * multiplier
        except (ValueError, TypeError) as e:
            # AI 辅助建议：提供详细的错误日志
            print(f"计算错误：{item} - {e}")
            return 0


