### 3.2 优化后的代码示例

javascript
// ============ 优化后的用户数据处理模块 ============

// 常量定义
const LEGAL_AGE_THRESHOLD = 18;
const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

// 用户数据
const users = [
  { id: 1, name: '张三', email: 'zhangsan@example.com', age: 28 },
  { id: 2, name: '李四', email: 'lisi@example.com', age: 35 },
  { id: 3, name: '王五', email: 'wangwu@example.com', age: 42 }
];

// 使用 Map 优化查找性能 O(1) vs O(n)
class UserRepository {
  constructor(userList) {
    // 创建索引，快速查找用户
    this.userById = new Map(userList.map(user => [user.id, user]));
  }

  findById(userId) {
    return this.userById.get(userId) || null;
  }

  findEligibleUsers() {
    return Array.from(this.userById.values())
      .filter(user => user.age >= LEGAL_AGE_THRESHOLD);
  }
}

// 邮箱验证函数
function isValidEmail(email) {
  return EMAIL_REGEX.test(email);
}

// 发送邮件函数（带验证）
async function sendEmail(email, content) {
  if (!isValidEmail(email)) {
    throw new Error(`无效的邮箱地址: ${email}`);
  }
  console.log('Sending email to:', email);
  // 实际发送邮件逻辑
  return true;
}

// 批量发送营销邮件（带完整错误处理）
async function sendMarketingEmails(userIds) {
  const repository = new UserRepository(users);
  const results = [];

  for (const userId of userIds) {
    const user = repository.findById(userId);

    if (!user) {
      results.push({ userId, success: false, reason: '用户不存在' });
      continue;
    }

    if (user.age < LEGAL_AGE_THRESHOLD) {
      results.push({ userId, success: false, reason: '年龄未达标' });
      continue;
    }

    try {
      await sendEmail(user.email, '营销内容');
      results.push({ userId, success: true });
    } catch (error) {
      console.error(`发送邮件失败 - 用户ID: ${userId}`, error);
      results.push({ userId, success: false, reason: error.message });
    }
  }

  return results;
}

// 使用示例
sendMarketingEmails([1, 2, 3]).then(results => {
  const successCount = results.filter(r => r.success).length;
  console.log(`成功: ${successCount}/${results.length}`);
});


