### 示例 2

```python
// 示例2：展示对话式编程的实际应用
    // 场景：在已有代码基础上进行重构

    // 原始代码（需要重构的）
    function processOrder(orderData) {
      let total = 0;
      let items = [];

      for (let i = 0; i < orderData.length; i++) {
        if (orderData[i].price > 0) {
          total += orderData[i].price * orderData[i].quantity;
          items.push({
            name: orderData[i].name,
            qty: orderData[i].quantity,
            subtotal: orderData[i].price * orderData[i].quantity
          });
        }
      }

      return {
        items: items,
        total: total,
        tax: total * 0.1,
        grandTotal: total * 1.1
      };
    }

    // 使用 Cursor Composer (Cmd+K) 输入:
    // "将这个订单处理函数重构为使用 map/filter 的函数式风格，
    //  提取验证逻辑，并添加 TypeScript 类型定义"

    // AI 生成的参考重构结果：
    interface OrderItem {
      name: string;
      price: number;
      quantity: number;
    }

    interface ProcessedOrder {
      items: ProcessedItem[];
      total: number;
      tax: number;
      grandTotal: number;
    }

    function validateOrderItem(item: OrderItem): boolean {
      return item.price > 0 && item.quantity > 0;
    }

    function processOrder(orderData: OrderItem[]): ProcessedOrder {
      const validItems = orderData.filter(validateOrderItem);

      const processedItems = validItems.map(item => ({
        name: item.name,
        qty: item.quantity,
        subtotal: item.price * item.quantity
      }));

      const total = processedItems.reduce((sum, item) => sum + item.subtotal, 0);
      const tax = total * 0.1;

      return {
        items: processedItems,
        total,
        tax,
        grandTotal: total + tax
      };
    }

    // 使用方式：选中原代码 -> Cmd+K -> 输入重构指令 -> 确认应用
