  describe('createUser', () => {
    test('应该成功创建用户并返回用户对象', () => {
      const user = userService.createUser('测试用户', 'test@example.com');

      expect(user).toBeDefined();
      expect(user.id).toBeDefined();
      expect(user.name).toBe('测试用户');
      expect(user.email).toBe('test@example.com');
      expect(user.createdAt).toBeInstanceOf(Date);
    });
  });

  describe('getUserById', () => {
    test('应该返回存在的用户', () => {
      const created = userService.createUser('查找测试', 'find@test.com');
      const found = userService.getUserById(created.id);

      expect(found).toEqual(created);
    });

    test('不存在的用户ID应返回null', () => {
      const result = userService.getUserById('non-existent-id');

      expect(result).toBeNull();
    });
  });

  describe('updateUser', () => {
    test('应该成功更新用户信息', () => {
      const original = userService.createUser('原名', 'original@email.com');
      const updated = userService.updateUser(original.id, { name: '新名字' });

      expect(updated.name).toBe('新名字');
      expect(updated.email).toBe('original@email.com');
      expect(updated.updatedAt).toBeInstanceOf(Date);
    });

    test('更新不存在的用户应返回null', () => {
      const result = userService.updateUser('fake-id', { name: '测试' });

      expect(result).toBeNull();
    });
  });

  describe('deleteUser', () => {
    test('应该成功删除用户', () => {
      const user = userService.createUser('待删除', 'delete@test.com');
      const deleted = userService.deleteUser(user.id);

      expect(deleted).toBe(true);
      expect(userService.getUserById(user.id)).toBeNull();
    });
  });
});


---

## 4. 常见问题与注意事项

### 常见错误

| 错误类型 | 具体表现 | 原因分析 |
|---------|---------|---------|
| 过度依赖 AI | 所有代码都等待 AI 生成 | 缺乏主动思考，效率反而降低 |
| 上下文缺失 | 生成代码与项目风格不匹配 | 没有提供足够的上下文信息 |
| 提示词模糊 | 生成的代码不符合预期 | 提示词不够具体明确 |
| 忽略类型错误 | 直接接受明显类型不匹配的代码 | 没有仔细检查 AI 输出 |
| 安全问题 | 使用 AI 生成的 SQL/命令直接执行 | 缺少安全意识，信任过度 |

### 注意事项

1. **始终审查 AI 生成的代码**：不要盲目接受，特别是涉及安全、权限、数据库操作的代码
2. **提供清晰的上下文**：在编写新功能前，确保相关文件已打开
3. **分步骤生成复杂功能**：不要期望一次生成完整的复杂模块
4. **注意代码风格一致性**：检查生成代码是否符合项目的编码规范
5. **测试是关键**：AI 生成的代码必须经过测试验证

---

## 5. 实践建议

### 最佳实践

#### 5.1 补全策略

- **利用 Inline 补全提升打字效率**：当看到灰色预览是正确时，继续输入即可自动接受
- **对于多行建议，使用 Tab 逐行接受**：不要一次性接受整个建议，除非你完全确定
- **组合使用快捷键**：
  - `Tab` 接受当前行
  - `Cmd/Ctrl + →` 接受整个建议
  - `Esc` 拒绝并清除

#### 5.2 提示词优化


# 不推荐 ❌
写一个函数

# 推荐 ✅
写一个函数来验证邮箱格式
参数：email string
返回：boolean
使用正则表达式实现


#### 5.3 工作流程建议

1. **先写注释描述意图** → AI 根据注释生成代码框架
2. **让 AI 生成后立即审查** → 检查逻辑正确性
3. **对生成代码进行微调** → 不满意的部分手动修改
4. **添加测试用例** → 使用 AI 辅助生成测试
5. **定期重构** → AI 生成代码可能不是最优解，需要持续优化

#### 5.4 项目级优化

- **保持项目文档更新**：添加 README 和类型定义
- **使用一致的命名规范**：帮助 AI 理解代码结构
- **定期运行 linter**：确保 AI 生成代码符合项目规范
- **建立代码模板库**：为常见模式创建模板

---

## 总结

掌握 Cursor AI 的智能代码生成与补全策略，是提升编程效率的关键。通过理解 Inline 补全与 Tab 补全的适用场景、学会编写有效的提示词、遵循最佳实践，你可以在保持代码质量的同时显著提升开发速度。记住：AI 是强大的辅助工具，但代码的主导权始终在你手中。

## 代码示例

### 示例 1

```python
// 示例1：利用 Cursor AI 生成数据处理管道
// 文件：dataProcessor.js

class DataProcessor {
  constructor() {
    this.pipeline = [];
  }

  // 添加处理步骤
  addStep(name, handler) {
    this.pipeline.push({ name, handler });
    return this; // 支持链式调用
  }

  // 执行处理管道
  async process(data) {
    let result = data;
    for (const step of this.pipeline) {
      try {
        result = await step.handler(result);
      } catch (error) {
        console.error(`步骤 "${step.name}" 执行失败:`, error);
        throw error;
      }
    }
    return result;
  }
}

// 使用示例
const processor = new DataProcessor();

processor
  .addStep('数据清洗', (data) => {
    return data.filter(item => item.value > 0);
  })
  .addStep('数据转换', (data) => {
    return data.map(item => ({
      ...item,
      normalized: item.value / 100
    }));
  })
  .addStep('数据聚合', async (data) => {
    return data.reduce((acc, item) => ({
      count: acc.count + 1,
      total: acc.total + item.value
    }), { count: 0, total: 0 });
  });

// 测试数据
const testData = [
  { id: 1, value: 50 },
  { id: 2, value: 150 },
  { id: 3, value: -20 }, // 会被过滤掉
  { id: 4, value: 80 }
];

processor.process(testData).then(result => {
  console.log('处理结果:', result);
  // 输出: { count: 3, total: 280 }
});
```

