/**
 * 用户注册验证模块
 * 负责所有与注册数据验证相关的逻辑
 */
class UserRegistrationValidator {
    // 邮箱格式正则表达式
    private static readonly EMAIL_PATTERN = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    // 最小密码长度
    private static readonly MIN_PASSWORD_LENGTH = 8;

    /**
     * 验证用户注册数据
     * @throws {ValidationError} 当验证失败时抛出
     */
    static validate(userData) {
        this.validateEmail(userData.email);
        this.validatePassword(userData.password);
        this.checkEmailAvailability(userData.email);
    }

    private static validateEmail(email) {
        if (!this.EMAIL_PATTERN.test(email)) {
            throw new ValidationError('Invalid email format');
        }
    }

    private static validatePassword(password) {
        if (password.length < this.MIN_PASSWORD_LENGTH) {
            throw new ValidationError(
                `Password must be at least ${this.MIN_PASSWORD_LENGTH} characters`
            );
        }
    }

    private static async checkEmailAvailability(email) {
        const existingUser = await db.findUserByEmail(email);
        if (existingUser) {
            throw new ValidationError('Email already registered');
        }
    }
}

/**
 * 用户仓储模块
 * 负责用户数据的持久化操作
 */
class UserRepository {
    async create(userData) {
        const hashedPassword = await bcrypt.hash(userData.password, 10);

        return await db.createUser({
            email: userData.email,
            password: hashedPassword,
            name: userData.name,
            createdAt: new Date()
        });
