// 示例：使用 Composer 创建用户认证模块时的类型定义
// types/user.ts

import { Document } from 'mongoose';

export interface IUser {
  username: string;
  email: string;
  passwordHash: string;
  createdAt: Date;
  updatedAt: Date;
}

export interface UserDocument extends IUser, Document {
  comparePassword(candidatePassword: string): Promise<boolean>;
}

export interface AuthToken {
  userId: string;
  token: string;
  expiresIn: number;
}

// 示例：相应的认证服务实现
// services/authService.ts

import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import { UserDocument, AuthToken } from '../types/user';

export class AuthService {
  // 创建新用户
  async createUser(username: string, email: string, password: string): Promise<UserDocument> {
    const passwordHash = await bcrypt.hash(password, 10);
    // 这里应该是实际的数据库保存逻辑
    const user = { username, email, passwordHash, createdAt: new Date() };
    return user as UserDocument;
  }

  // 用户登录
  async login(email: string, password: string): Promise<AuthToken> {
    // 查找用户、验证密码的逻辑
    const token = jwt.sign({ userId: 'user._id' }, process.env.JWT_SECRET || 'secret', {
      expiresIn: '7d'
    });
    return {
      userId: 'user._id',
      token,
      expiresIn: 7 * 24 * 60 * 60 // 7天
    };
  }

  // Token 验证
  verifyToken(token: string): { userId: string } {
    return jwt.verify(token, process.env.JWT_SECRET || 'secret') as { userId: string };
  }
}

export const authService = new AuthService();

// 示例：认证中间件
// middleware/auth.ts

import { Request, Response, NextFunction } from 'express';
import { authService } from '../services/authService';

export interface AuthRequest extends Request {
  userId?: string;
}

export const authMiddleware = async (
  req: AuthRequest,
  res: Response,
  next: NextFunction
): Promise<void> => {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      res.status(401).json({ error: '未提供认证令牌' });
      return;
    }

    const token = authHeader.substring(7);
    const decoded = authService.verifyToken(token);
    req.userId = decoded.userId;
    next();
  } catch (error) {
    res.status(401).json({ error: '无效的认证令牌' });
  }
};

// 示例：路由定义
// routes/userRoutes.ts

import { Router } from 'express';
import { authService } from '../services/authService';
import { authMiddleware, AuthRequest } from '../middleware/auth';

const router = Router();

// 注册
router.post('/register', async (req, res) => {
  const { username, email, password } = req.body;
  try {
    const user = await authService.createUser(username, email, password);
    res.status(201).json({ message: '用户创建成功', user });
  } catch (error: any) {
    res.status(400).json({ error: error.message });
  }
});

// 登录
router.post('/login', async (req, res) => {
  const { email, password } = req.body;
  try {
    const authToken = await authService.login(email, password);
    res.json({ token: authToken.token, expiresIn: authToken.expiresIn });
  } catch (error: any) {
    res.status(401).json({ error: '认证失败' });
  }
});

// 获取当前用户信息（需要认证）
router.get('/me', authMiddleware, async (req: AuthRequest, res) => {
  res.json({ userId: req.userId });
});

export default router;
```

