// API 集成示例 - 使用 Cursor AI 生成带完整错误处理的请求工具
import axios, { AxiosInstance, AxiosError, AxiosRequestConfig } from 'axios';

// 创建 axios 实例
const apiClient: AxiosInstance = axios.create({
  baseURL: import.meta.env.VITE_API_BASE_URL || 'http://localhost:3000/api',
  timeout: 10000,
  headers: {
    'Content-Type': 'application/json'
  }
});

// 请求拦截器 - 添加认证 token
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('auth_token');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);

// 响应拦截器 - 统一错误处理
apiClient.interceptors.response.use(
  (response) => response.data,
  async (error: AxiosError) => {
    const originalRequest = error.config as AxiosRequestConfig & { _retryCount?: number };

    // 处理 401 未授权 - 尝试刷新 token
    if (error.response?.status === 401 && !originalRequest._retryCount) {
      originalRequest._retryCount = 0;

      try {
        const refreshToken = localStorage.getItem('refresh_token');
        if (refreshToken) {
          // 调用刷新 token 接口
          const response = await axios.post('/api/auth/refresh', { refreshToken });
          const { token } = response.data;

          localStorage.setItem('auth_token', token);
          originalRequest.headers!.Authorization = `Bearer ${token}`;

          return apiClient(originalRequest);
        }
      } catch (refreshError) {
        // 刷新失败，跳转登录
        localStorage.clear();
        window.location.href = '/login';
      }
    }

    // 统一的错误提示
    const errorMessage = extractErrorMessage(error);
    console.error('API Error:', errorMessage);

    // 可以使用 toast 或 notification 组件显示错误
    // showErrorToast(errorMessage);

    return Promise.reject(error);
  }
);

// 辅助函数 - 提取错误信息
function extractErrorMessage(error: AxiosError): string {
  if (error.response?.data) {
    const { message, error: errorCode } = error.response.data as any;
    return message || errorCode || '服务器错误';
  }

  if (error.code === 'ECONNABORTED') {
    return '请求超时，请重试';
  }

  if (!navigator.onLine) {
    return '网络连接已断开';
  }

  return '网络错误，请检查网络连接';
}

// API 接口模块示例
export const userApi = {
  // 获取用户列表
  list: (params: { page?: number; pageSize?: number }) => 
    apiClient.get('/users', { params }),

  // 获取单个用户
