    apiClient.post('/users', data),

  // 更新用户
  update: (id: string, data: Partial<{ name: string; email: string }>) => 
    apiClient.patch(`/users/${id}`, data),

  // 删除用户
  delete: (id: string) => 
    apiClient.delete(`/users/${id}`)
};

export default apiClient;

