// models/User.js - 用户数据模型
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

const userSchema = new mongoose.Schema({
  username: {
    type: String,
    required: [true, '用户名不能为空'],
    unique: true,
    trim: true,
    minlength: [3, '用户名至少3个字符'],
    maxlength: [20, '用户名最多20个字符'],
    index: true
  },
  email: {
    type: String,
    required: [true, '邮箱不能为空'],
    unique: true,
    lowercase: true,
    trim: true,
    match: [/^\w+([.-]?\w+)*@\w+([.-]?\w+)*(\.\w{2,3})+$/, '邮箱格式不正确']
  },
  password: {
    type: String,
    required: [true, '密码不能为空'],
    minlength: [6, '密码至少6个字符'],
    select: false // 默认不返回密码字段
  },
  role: {
    type: String,
    enum: ['user', 'admin', 'moderator'],
    default: 'user'
  },
  profile: {
    avatar: String,
    bio: { type: String, maxlength: 500 },
    website: String
  },
  status: {
    type: String,
    enum: ['active', 'inactive', 'banned'],
    default: 'active'
  },
  lastLogin: Date,
  loginAttempts: { type: Number, default: 0 },
  lockUntil: Date
}, {
  timestamps: true, // 自动管理 createdAt 和 updatedAt
  toJSON: { virtuals: true },
  toObject: { virtuals: true }
});

// 密码加密中间件
userSchema.pre('save', async function(next) {
  // 只在密码被修改时重新加密
  if (!this.isModified('password')) return next();

  try {
    const salt = await bcrypt.genSalt(12);
    this.password = await bcrypt.hash(this.password, salt);
    next();
  } catch (error) {
    next(error);
  }
});

// 密码验证方法
userSchema.methods.comparePassword = async function(candidatePassword) {
  return bcrypt.compare(candidatePassword, this.password);
};

// 账户锁定逻辑
userSchema.methods.isLocked = function() {
  return !!(this.lockUntil && this.lockUntil > Date.now());
};

// 虚拟字段
userSchema.virtual('profileUrl').get(function() {
  return `/users/${this._id}/profile`;
});

// 静态方法 - 按邮箱查找
userSchema.statics.findByEmail = function(email) {
  return this.findOne({ email: email.toLowerCase() });
};

// 静态方法 - 获取活跃用户列表
userSchema.statics.getActiveUsers = function(page = 1, limit = 20) {
  return this.find({ status: 'active' })
    .select('-password')
    .skip((page - 1) * limit)
    .limit(limit)
    .sort({ createdAt: -1 });
};

// 索引
userSchema.index({ email: 1, status: 1 });
userSchema.index({ createdAt: -1 });

const User = mongoose.model('User', userSchema);

module.exports = User;


#### 示例 3：业务逻辑服务层

javascript
// services/userService.js - 用户服务层
const User = require('../models/User');
const CacheService = require('./cacheService');
const { AppError } = require('../utils/errors');

class UserService {
  constructor() {
    this.cache = new CacheService();
    this.CACHE_TTL = 3600; // 1小时
  }


  /**
   * 创建新用户
   * @param {Object} userData - 用户数据
   * @returns {Promise<Object>} 创建的用户对象
   */
  async createUser(userData) {
    try {
      // 检查邮箱是否已被使用
      const existingUser = await User.findByEmail(userData.email);
      if (existingUser) {
        throw new AppError('该邮箱已被注册', 400, 'EMAIL_EXISTS');
      }

      // 检查用户名是否已被使用
      const existingUsername = await User.findOne({ 
        username: userData.username 
      });
      if (existingUsername) {
        throw new AppError('该用户名已被使用', 400, 'USERNAME_EXISTS');
      }

      const user = new User(userData);
      await user.save();

      // 生成 JWT token
      const token = user.generateAuthToken();

      // 缓存用户基本信息
      await this.cache.set(`user:${user._id}`, user.toPublicJSON(), this.CACHE_TTL);

      return {
        user: user.toPublicJSON(),
        token
      };
    } catch (error) {
      if (error.code === 11000) {
        throw new AppError('用户已存在', 400, 'USER_EXISTS');
      }
      throw error;
    }
  }

  /**
   * 用户登录
   * @param {string} email - 邮箱
   * @param {string} password - 密码
   * @returns {Promise<Object>} 登录结果
   */
  async login(email, password) {
    const user = await User.findByEmail(email).select('+password');

    if (!user) {
      throw new AppError('邮箱或密码错误', 401, 'INVALID_CREDENTIALS');
    }

    if (user.status === 'banned') {
      throw new AppError('账户已被禁用', 403, 'ACCOUNT_BANNED');
    }

    // 检查账户锁定状态
    if (user.isLocked()) {
      throw new AppError(
        `账户已锁定，请 ${Math.ceil((user.lockUntil - Date.now()) / 60000)} 分钟后重试`,
        423,
        'ACCOUNT_LOCKED'
      );
    }

    const isMatch = await user.comparePassword(password);

    if (!isMatch) {
      // 增加登录失败次数
      user.loginAttempts += 1;
      if (user.loginAttempts >= 5) {
        user.lockUntil = new Date(Date.now() + 30 * 60 * 1000); // 锁定30分钟
      }
      await user.save();
      throw new AppError('邮箱或密码错误', 401, 'INVALID_CREDENTIALS');
    }

    // 重置登录失败次数
    user.loginAttempts = 0;
    user.lockUntil = undefined;
    user.lastLogin = new Date();
    await user.save();

    const token = user.generateAuthToken();

    return {
      user: user.toPublicJSON(),
      token
    };
  }

  /**
   * 获取用户详情
   * @param {string} userId - 用户ID
   * @returns {Promise<Object>} 用户详情
   */
  async getUserById(userId) {
    // 先从缓存获取
    const cached = await this.cache.get(`user:${userId}`);
    if (cached) {
      return cached;
    }

    const user = await User.findById(userId);
    if (!user) {
      throw new AppError('用户不存在', 404, 'USER_NOT_FOUND');
    }

    // 存入缓存
    await this.cache.set(`user:${userId}`, user.toPublicJSON(), this.CACHE_TTL);

    return user.toPublicJSON();
  }

  /**
   * 更新用户信息
   * @param {string} userId - 用户ID
   * @param {Object} updateData - 更新数据
   * @returns {Promise<Object>} 更新后的用户
   */
  async updateUser(userId, updateData) {
    const allowedUpdates = ['profile', 'email', 'username'];
    const updates = Object.keys(updateData)
      .filter(key => allowedUpdates.includes(key))
      .reduce((obj, key) => {
        obj[key] = updateData[key];
        return obj;
      }, {});

    if (Object.keys(updates).length === 0) {
      throw new AppError('没有有效的更新字段', 400, 'NO_UPDATES');
    }

    const user = await User.findByIdAndUpdate(
      userId,
      updates,
      { new: true, runValidators: true }
    );

    if (!user) {
      throw new AppError('用户不存在', 404, 'USER_NOT_FOUND');
    }

    // 清除缓存
    await this.cache.del(`user:${userId}`);

    return user.toPublicJSON();
  }

  /**
   * 删除用户（软删除）
   * @param {string} userId - 用户ID
   * @returns {Promise<void>}
   */
  async deleteUser(userId) {
    const user = await User.findByIdAndUpdate(
      userId,
      { status: 'inactive' },
      { new: true }
    );

    if (!user) {
      throw new AppError('用户不存在', 404, 'USER_NOT_FOUND');
    }

    // 清除缓存
    await this.cache.del(`user:${userId}`);
  }
}

module.exports = new UserService();


#### 示例 4：认证中间件

javascript
// middleware/auth.js - 认证与授权中间件
const jwt = require('jsonwebtoken');
const User = require('../models/User');
const { AppError } = require('../utils/errors');

/**
 * JWT 验证中间件
 * 验证请求头中的 Bearer Token
 */
const authenticate = async (req, res, next) => {
  try {
    // 获取 Token
    let token;
    if (req.headers.authorization?.startsWith('Bearer')) {
      token = req.headers.authorization.split(' ')[1];
    }

    if (!token) {
      throw new AppError('请先登录以访问此资源', 401, 'NO_TOKEN');
    }

    // 验证 Token
    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // 检查用户是否仍然存在
    const user = await User.findById(decoded.id);
    if (!user) {
      throw new AppError('用户不存在', 401, 'USER_NOT_EXIST');
    }

    // 检查用户状态
    if (user.status === 'banned') {
      throw new AppError('账户已被禁用', 403, 'ACCOUNT_BANNED');
    }

    if (user.status === 'inactive') {
      throw new AppError('账户已被注销', 401, 'ACCOUNT_INACTIVE');
    }

    // 将用户信息附加到请求对象
    req.user = user;
    req.userId = user._id;


    next();
  } catch (error) {
    if (error.name === 'JsonWebTokenError') {
      return next(new AppError('Token 无效', 401, 'INVALID_TOKEN'));
    }
    if (error.name === 'TokenExpiredError') {
      return next(new AppError('Token 已过期', 401, 'TOKEN_EXPIRED'));
    }
    next(error);
  }
};

/**
 * 角色授权中间件工厂
 * @param {...string} allowedRoles - 允许访问的角色列表
 * @returns {Function} 中间件函数
 */
const authorize = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return next(new AppError('用户未认证', 401, 'NOT_AUTHENTICATED'));
    }

    if (!allowedRoles.includes(req.user.role)) {
      return next(new AppError(
        `此操作需要 ${allowedRoles.join(' 或 ')} 权限`,
        403,
        'INSUFFICIENT_PERMISSIONS'
      ));
    }

    next();
  };
};

/**
 * 资源所有者验证中间件
 * 确保用户只能操作自己的资源
 */
const checkOwnership = (paramKey = 'id') => {
  return (req, res, next) => {
    const resourceId = req.params[paramKey];
    const userId = req.user._id.toString();


    // 检查是否为资源所有者或管理员
    if (resourceId !== userId && req.user.role !== 'admin') {
      return next(new AppError('无权访问此资源', 403, 'NOT_OWNER'));
    }

    next();
  };
};

module.exports = {
  authenticate,
  authorize,
  checkOwnership
};


### 四、常见问题与注意事项


#### 常见错误

1. **过度依赖 AI 生成代码**：AI 生成的代码虽然可用，但可能不适合特定业务场景，需要理解后再使用
2. **忽视错误处理**：生成的代码有时缺少完整的错误处理逻辑，需要手动补充
3. **安全漏洞**：AI 可能生成存在安全风险的代码（如 SQL 注入、XSS），必须进行安全审查
4. **性能问题**：批量操作时可能生成 N+1 查询问题，需要优化数据库访问
5. **版本兼容性**：AI 生成的代码可能依赖特定版本，需确认环境配置

#### 注意事项

- **代码审查**：所有 AI 生成的代码必须经过人工审查
- **安全第一**：特别关注认证、授权、数据验证等安全相关代码
- **测试覆盖**：为 AI 生成的代码编写充分的单元测试和集成测试
- **环境配置**：确保开发环境与生产环境一致
- **日志记录**：添加适当的日志便于问题排查

### 五、实践建议

#### 高效使用 Cursor AI 进行后端开发

1. **明确项目结构**：在使用 AI 之前，先建立清晰的项目目录结构
2. **提供完整上下文**：向 AI 提供相关文件内容和需求描述
3. **分步骤生成**：先生成模型，再生成服务层，最后生成路由
4. **持续优化**：对生成的代码进行重构和优化
5. **建立代码规范**：创建团队代码规范文档，让 AI 遵循

#### 推荐的工作流程


1. 定义数据模型 → 2. 实现 CRUD 操作 → 3. 编写业务逻辑 → 
4. 配置路由和中间件 → 5. 添加错误处理 → 6. 编写测试


#### 学习资源建议

- 深入学习 RESTful API 设计规范
- 掌握至少一种数据库操作（MongoDB/PostgreSQL）
- 了解常见的安全威胁和防御措施
