### 示例 2：跨文件依赖分析

typescript
// src/services/userService.ts
// 演示如何通过索引理解跨文件依赖

import { Database } from './database';
import { CacheManager } from './cache';
import { Logger } from '../utils/logger';
import { EventEmitter } from 'events';

class UserService extends EventEmitter {
  private db: Database;
  private cache: CacheManager;

  constructor() {
    super();
    this.db = new Database();
    this.cache = CacheManager.getInstance();
  }

  async getUserById(id: string): Promise<User | null> {
    // 1. 先检查缓存
    const cached = await this.cache.get(`user:${id}`);
    if (cached) {
      Logger.info(`Cache hit for user ${id}`);
      return cached;
    }

    // 2. 缓存未命中，查询数据库
    const user = await this.db.query(
      'SELECT * FROM users WHERE id = ?',
      [id]
    );

    // 3. 结果存入缓存
    if (user) {
      await this.cache.set(`user:${id}`, user, { ttl: 3600 });
      this.emit('user:fetched', user);
    }

    return user;
  }

  async updateUser(id: string, data: Partial<User>): Promise<void> {
    await this.db.update('users', data, { where: { id } });
    // 使缓存失效
    await this.cache.delete(`user:${id}`);
    this.emit('user:updated', { id, data });
  }
}

// Cursor 索引会理解:
// - UserService 依赖 Database, CacheManager, Logger
// - getUserById 方法会触发 'user:fetched' 事件
// - updateUser 方法会使缓存失效
// - 这两个方法都依赖数据库查询

export const userService = new UserService();


typescript
// src/routes/userRoutes.ts
// 展示 AI 如何追踪依赖链

import { Router } from 'express';
import { userService } from '../services/userService';

const router = Router();

// 当 Cursor 理解这个文件时，它会:
// 1. 识别 userService.getUserById 的调用
// 2. 追踪到 UserService 类的实现
// 3. 理解整个调用链: Router → userService → Database/Cache

router.get('/users/:id', async (req, res) => {
  try {
    const user = await userService.getUserById(req.params.id);
    if (!user) {
      return res.status(404).json({ error: 'User not found' });
    }
    res.json(user);
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

router.patch('/users/:id', async (req, res) => {
  try {
    await userService.updateUser(req.params.id, req.body);
    res.json({ success: true });
  } catch (error) {
    res.status(500).json({ error: 'Internal server error' });
  }
});

export default router;


