# 示例：修改前 (Vue 2 Options API)
/*
 * UserCard.vue
 * 用于展示用户信息卡片
 * @author: Developer Team
 * @updated: 2024-01-15
 */
export default {
    name: 'UserCard',
    props: {
        userId: {
            type: Number,
            required: true
        }
    },
    data() {
        return {
            userName: '',
            userEmail: '',
            isLoading: false
        };
    },
    computed: {
        userInfo() {
