      const mockHandler = jest.fn(x => x);
      processor.addStep('测试步骤', mockHandler);

      expect(processor.pipeline[0]).toEqual({
        name: '测试步骤',
        handler: mockHandler
      });
    });
  });

  describe('process', () => {
    test('应该按顺序执行所有步骤', async () => {
      const executionOrder = [];

      processor
        .addStep('步骤A', (data) => {
          executionOrder.push('A');
          return data;
        })
        .addStep('步骤B', (data) => {
          executionOrder.push('B');
          return data;
        });

      await processor.process([1, 2, 3]);

      expect(executionOrder).toEqual(['A', 'B']);
    });

    test('应该处理异步步骤', async () => {
      processor.addStep('异步步骤', async (data) => {
        return new Promise(resolve => {
          setTimeout(() => resolve(data.map(x => x * 2)), 10);
        });
      });

      const result = await processor.process([1, 2, 3]);
      expect(result).toEqual([2, 4, 6]);
    });

    test('步骤执行失败应该抛出错误', async () => {
      processor.addStep('失败步骤', () => {
        throw new Error('执行失败');
      });

      await expect(processor.process([1]))
        .rejects.toThrow('执行失败');
    });

    test('空管道应该直接返回原数据', async () => {
      const data = [1, 2, 3];
      const result = await processor.process(data);

      expect(result).toEqual(data);
    });
  });
