# 支付处理器 - 使用大量条件判断处理不同支付方式
class PaymentProcessor:
    def process_payment(self, order, payment_method, payment_details):
        if payment_method == 'credit_card':
            # 信用卡处理逻辑
            card = self.load_card(payment_details['card_number'])
            if card.is_expired():
                raise PaymentError('Card expired')
            if card.balance < order.total:
                raise PaymentError('Insufficient balance')
            card.charge(order.total)
            self.record_transaction(order.id, 'credit_card', order.total)
            return {'status': 'success', 'transaction_id': card.transaction_id}

        elif payment_method == 'paypal':
            # PayPal 处理逻辑
            paypal_account = self.verify_paypal(payment_details['email'])
            if not paypal_account:
                raise PaymentError('Invalid PayPal account')
            paypal_account.execute_payment(order.total)
            self.record_transaction(order.id, 'paypal', order.total)
            return {'status': 'success', 'transaction_id': paypal_account.transaction_id}

        elif payment_method == 'bank_transfer':
            # 银行转账处理逻辑
            bank_account = self.validate_bank_account(payment_details['account_number'])
            if not bank_account:
                raise PaymentError('Invalid bank account')
            bank_account.transfer(order.total)
            self.record_transaction(order.id, 'bank_transfer', order.total)
            return {'status': 'success', 'transaction_id': bank_account.transaction_id}

        elif payment_method == 'crypto':
            # 加密货币处理逻辑
            wallet = self.get_crypto_wallet(payment_details['wallet_address'])
            if not self.validate_crypto_transaction(wallet, order.total):
                raise PaymentError('Crypto transaction failed')
            wallet.confirm_transaction(order.total)
            self.record_transaction(order.id, 'crypto', order.total)
            return {'status': 'success', 'transaction_id': wallet.transaction_id}

        else:
            raise PaymentError(f'Unsupported payment method: {payment_method}')


**使用 AI 辅助重构为策略模式**：

python
# AI 建议：使用策略模式重构支付处理逻辑
# 核心思想：将每种支付方式封装为独立的策略类

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, Any
from enum import Enum


class PaymentStatus(Enum):
    """支付状态枚举"""
    SUCCESS = 'success'
    FAILED = 'failed'
    PENDING = 'pending'


@dataclass
class PaymentResult:
    """支付结果数据类"""
    status: PaymentStatus
    transaction_id: str = None
    message: str = None


class PaymentError(Exception):
    """支付异常类"""
    pass


class PaymentStrategy(ABC):
    """
    支付策略抽象基类
    定义所有支付方式必须实现的接口
    """

    @property
    @abstractmethod
    def method_name(self) -> str:
        """支付方式名称"""
        pass

    @abstractmethod
    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """
        验证支付详情
        @raises PaymentError: 验证失败时抛出
        """
        pass

    @abstractmethod
    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """
        执行支付
        @param amount: 支付金额
        @param order_id: 订单ID
        @return PaymentResult: 支付结果
        """
        pass


class CreditCardPaymentStrategy(PaymentStrategy):
    """信用卡支付策略"""

    def __init__(self, card_loader, transaction_recorder):
        self.card_loader = card_loader
        self.transaction_recorder = transaction_recorder

    @property
    def method_name(self) -> str:
        return 'credit_card'

    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """验证信用卡信息"""
        card = self.card_loader.load(payment_details['card_number'])

        if card.is_expired():
            raise PaymentError('Card expired')

        if not card.is_valid():
            raise PaymentError('Invalid card')

    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """执行信用卡支付"""
        card = self.card_loader.get_current_card()

        if card.balance < amount:
            raise PaymentError('Insufficient balance')

        transaction_id = card.charge(amount)
        self.transaction_recorder.record(order_id, self.method_name, amount)

        return PaymentResult(
            status=PaymentStatus.SUCCESS,
            transaction_id=transaction_id
        )


class PayPalPaymentStrategy(PaymentStrategy):
    """PayPal 支付策略"""

    def __init__(self, paypal_client, transaction_recorder):
        self.paypal_client = paypal_client
        self.transaction_recorder = transaction_recorder

    @property
    def method_name(self) -> str:
        return 'paypal'

    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """验证 PayPal 账户"""
        account = await self.paypal_client.verify_account(
            payment_details['email']
        )
        if not account:
            raise PaymentError('Invalid PayPal account')

    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """执行 PayPal 支付"""
        transaction_id = await self.paypal_client.execute_payment(amount)
        self.transaction_recorder.record(order_id, self.method_name, amount)

        return PaymentResult(
            status=PaymentStatus.SUCCESS,
            transaction_id=transaction_id
        )


class CryptoPaymentStrategy(PaymentStrategy):
    """加密货币支付策略"""

    def __init__(self, wallet_service, transaction_validator, transaction_recorder):
        self.wallet_service = wallet_service
        self.transaction_validator = transaction_validator
        self.transaction_recorder = transaction_recorder

    @property
    def method_name(self) -> str:
        return 'crypto'

    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """验证加密货币钱包"""
        self.wallet_service.get_wallet(payment_details['wallet_address'])

    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """执行加密货币支付"""
        wallet = self.wallet_service.get_current_wallet()

        if not await self.transaction_validator.validate(wallet, amount):
            raise PaymentError('Crypto transaction failed')

        transaction_id = await wallet.confirm_transaction(amount)
        self.transaction_recorder.record(order_id, self.method_name, amount)

        return PaymentResult(
            status=PaymentStatus.SUCCESS,
            transaction_id=transaction_id
        )


class PaymentContext:
    """
    支付上下文
    负责管理支付策略并执行支付流程
    """

    def __init__(self, strategy: PaymentStrategy):
        self._strategy = strategy

    @property
    def strategy(self) -> PaymentStrategy:
        return self._strategy

    @strategy.setter
    def strategy(self, strategy: PaymentStrategy):
        """支持动态切换支付策略"""
        self._strategy = strategy

    async def process(self, order, payment_details) -> PaymentResult:
        """
        执行支付处理流程
        1. 验证支付详情
        2. 执行支付
        3. 返回结果
        """
        # 验证阶段
        await self._strategy.validate(payment_details)

        # 执行阶段
        return await self._strategy.execute(
            amount=order.total,
            order_id=order.id
        )


class PaymentProcessor:
    """
    支付处理器
    负责根据支付方式选择合适的策略并处理支付
    """

    def __init__(self, payment_gateway, transaction_recorder):
        self.payment_gateway = payment_gateway
        self.transaction_recorder = transaction_recorder
        self._strategies: Dict[str, PaymentStrategy] = {}
        self._initialize_strategies()

    def _initialize_strategies(self):
        """初始化所有支付策略"""
        self._strategies['credit_card'] = CreditCardPaymentStrategy(
            self.payment_gateway.card_loader,
            self.transaction_recorder
        )
        self._strategies['paypal'] = PayPalPaymentStrategy(
            self.payment_gateway.paypal_client,
            self.transaction_recorder
        )
        self._strategies['crypto'] = CryptoPaymentStrategy(
            self.payment_gateway.wallet_service,
            self.payment_gateway.transaction_validator,
            self.transaction_recorder
        )

    async def process_payment(self, order, payment_method: str, payment_details: dict) -> PaymentResult:
        """
        处理支付请求

        Args:
            order: 订单对象
            payment_method: 支付方式
            payment_details: 支付详情

        Returns:
            PaymentResult: 支付结果

        Raises:
            PaymentError: 当支付方式不支持或处理失败时抛出
        """
        strategy = self._strategies.get(payment_method)

        if not strategy:
            raise PaymentError(f'Unsupported payment method: {payment_method}')

        context = PaymentContext(strategy)
        return await context.process(order, payment_details)


# 使用示例
async def main():
    """示例：使用重构后的支付处理器"""
    payment_gateway = PaymentGateway()
    transaction_recorder = TransactionRecorder()

    processor = PaymentProcessor(payment_gateway, transaction_recorder)

    # 处理信用卡支付
    result = await processor.process_payment(
        order=Order(id='123', total=99.99),
        payment_method='credit_card',
        payment_details={'card_number': '4111111111111111'}
    )
    print(f'Payment result: {result.status}')


## 4. 常见问题与注意事项

### 重构过程中的风险

| 风险类型 | 描述 | 控制措施 |
|---------|------|---------|
| 行为改变 | 重构可能无意间改变代码的外部行为 | 保持原有功能不变，通过测试验证 |
| 依赖破坏 | 修改接口可能影响调用方 | 使用渐进式重构，保持向后兼容 |
| 性能退化 | 某些重构可能引入性能问题 | 关注性能指标，必要时进行基准测试 |
| 边界遗漏 | 重构时可能遗漏某些边界情况 | 全面的测试覆盖，审查所有代码路径 |

### AI 辅助重构的注意事项

1. **保持测试通过**
   - 重构前确保有完整的测试覆盖
   - 每次小步重构后运行测试验证
   - AI 生成的代码同样需要测试

2. **理解改动范围**
   - 在接受 AI 建议前，理解改动的全貌
   - 确认是否需要同步修改其他文件
   - 警惕跨文件的隐式依赖

3. **保留版本历史**
   - 每次重构前提交代码
   - 使用清晰的提交信息记录重构内容
   - 便于出问题时的回溯

4. **避免过度重构**
   - 不是所有代码都需要重构
   - 关注投入产出比
   - 警惕"完美主义"陷阱

5. **审查 AI 建议**
   - AI 可能不理解业务上下文
   - 检查生成的代码是否符合项目规范
   - 验证边界情况的处理

## 5. 实践建议

### 有效使用 Cursor AI 进行重构

**推荐的对话策略**：


1. 明确表达重构目标
   ✓ "请将 calculate_order_total 函数拆分为计算折扣和应用折扣两个函数"
   ✗ "重构这段代码"

2. 逐步进行重构
   ✓ "首先帮我重命名这个变量"
   ✓ "现在将这个 if-else 链改为使用策略模式"
