        tax_rate=0.13       # 13%税率
    )

    print(f'小计: ¥{result.subtotal}')
    print(f'折扣: -¥{result.discount_amount}')
    print(f'税额: +¥{result.tax_amount}')
    print(f'总计: ¥{result.total}')
