# 支付处理器 - 使用大量条件判断处理不同支付方式
class PaymentProcessor:
    def process_payment(self, order, payment_method, payment_details):
        if payment_method == 'credit_card':
            # 信用卡处理逻辑
            card = self.load_card(payment_details['card_number'])
            if card.is_expired():
                raise PaymentError('Card expired')
            if card.balance < order.total:
                raise PaymentError('Insufficient balance')
            card.charge(order.total)
            self.record_transaction(order.id, 'credit_card', order.total)
            return {'status': 'success', 'transaction_id': card.transaction_id}

        elif payment_method == 'paypal':
            # PayPal 处理逻辑
            paypal_account = self.verify_paypal(payment_details['email'])
            if not paypal_account:
                raise PaymentError('Invalid PayPal account')
            paypal_account.execute_payment(order.total)
            self.record_transaction(order.id, 'paypal', order.total)
            return {'status': 'success', 'transaction_id': paypal_account.transaction_id}

        elif payment_method == 'bank_transfer':
            # 银行转账处理逻辑
            bank_account = self.validate_bank_account(payment_details['account_number'])
            if not bank_account:
                raise PaymentError('Invalid bank account')
            bank_account.transfer(order.total)
            self.record_transaction(order.id, 'bank_transfer', order.total)
            return {'status': 'success', 'transaction_id': bank_account.transaction_id}

        elif payment_method == 'crypto':
            # 加密货币处理逻辑
            wallet = self.get_crypto_wallet(payment_details['wallet_address'])
            if not self.validate_crypto_transaction(wallet, order.total):
                raise PaymentError('Crypto transaction failed')
            wallet.confirm_transaction(order.total)
            self.record_transaction(order.id, 'crypto', order.total)
            return {'status': 'success', 'transaction_id': wallet.transaction_id}

        else:
            raise PaymentError(f'Unsupported payment method: {payment_method}')


