# AI 建议：使用策略模式重构支付处理逻辑
# 核心思想：将每种支付方式封装为独立的策略类

from abc import ABC, abstractmethod
from dataclasses import dataclass
from typing import Dict, Any
from enum import Enum


class PaymentStatus(Enum):
    """支付状态枚举"""
    SUCCESS = 'success'
    FAILED = 'failed'
    PENDING = 'pending'


@dataclass
class PaymentResult:
    """支付结果数据类"""
    status: PaymentStatus
    transaction_id: str = None
    message: str = None


class PaymentError(Exception):
    """支付异常类"""
    pass


class PaymentStrategy(ABC):
    """
    支付策略抽象基类
    定义所有支付方式必须实现的接口
    """

    @property
    @abstractmethod
    def method_name(self) -> str:
        """支付方式名称"""
        pass

    @abstractmethod
    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """
        验证支付详情
        @raises PaymentError: 验证失败时抛出
        """
        pass

    @abstractmethod
    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """
        执行支付
        @param amount: 支付金额
        @param order_id: 订单ID
        @return PaymentResult: 支付结果
        """
        pass


class CreditCardPaymentStrategy(PaymentStrategy):
    """信用卡支付策略"""

    def __init__(self, card_loader, transaction_recorder):
        self.card_loader = card_loader
        self.transaction_recorder = transaction_recorder

    @property
    def method_name(self) -> str:
        return 'credit_card'

    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """验证信用卡信息"""
        card = self.card_loader.load(payment_details['card_number'])

        if card.is_expired():
            raise PaymentError('Card expired')

        if not card.is_valid():
            raise PaymentError('Invalid card')

    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """执行信用卡支付"""
        card = self.card_loader.get_current_card()

        if card.balance < amount:
            raise PaymentError('Insufficient balance')

        transaction_id = card.charge(amount)
        self.transaction_recorder.record(order_id, self.method_name, amount)

        return PaymentResult(
            status=PaymentStatus.SUCCESS,
            transaction_id=transaction_id
        )


class PayPalPaymentStrategy(PaymentStrategy):
    """PayPal 支付策略"""

    def __init__(self, paypal_client, transaction_recorder):
        self.paypal_client = paypal_client
        self.transaction_recorder = transaction_recorder

    @property
    def method_name(self) -> str:
        return 'paypal'

    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """验证 PayPal 账户"""
        account = await self.paypal_client.verify_account(
            payment_details['email']
        )
        if not account:
            raise PaymentError('Invalid PayPal account')

    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """执行 PayPal 支付"""
        transaction_id = await self.paypal_client.execute_payment(amount)
        self.transaction_recorder.record(order_id, self.method_name, amount)

        return PaymentResult(
            status=PaymentStatus.SUCCESS,
            transaction_id=transaction_id
        )


class CryptoPaymentStrategy(PaymentStrategy):
    """加密货币支付策略"""

    def __init__(self, wallet_service, transaction_validator, transaction_recorder):
        self.wallet_service = wallet_service
        self.transaction_validator = transaction_validator
        self.transaction_recorder = transaction_recorder

    @property
    def method_name(self) -> str:
        return 'crypto'

    async def validate(self, payment_details: Dict[str, Any]) -> None:
        """验证加密货币钱包"""
        self.wallet_service.get_wallet(payment_details['wallet_address'])

    async def execute(self, amount: float, order_id: str) -> PaymentResult:
        """执行加密货币支付"""
        wallet = self.wallet_service.get_current_wallet()

        if not await self.transaction_validator.validate(wallet, amount):
            raise PaymentError('Crypto transaction failed')

        transaction_id = await wallet.confirm_transaction(amount)
        self.transaction_recorder.record(order_id, self.method_name, amount)

        return PaymentResult(
            status=PaymentStatus.SUCCESS,
            transaction_id=transaction_id
        )


class PaymentContext:
    """
    支付上下文
    负责管理支付策略并执行支付流程
    """

    def __init__(self, strategy: PaymentStrategy):
        self._strategy = strategy

    @property
    def strategy(self) -> PaymentStrategy:
        return self._strategy

    @strategy.setter
    def strategy(self, strategy: PaymentStrategy):
        """支持动态切换支付策略"""
        self._strategy = strategy

    async def process(self, order, payment_details) -> PaymentResult:
        """
        执行支付处理流程
        1. 验证支付详情
        2. 执行支付
        3. 返回结果
        """
        # 验证阶段
        await self._strategy.validate(payment_details)

        # 执行阶段
        return await self._strategy.execute(
            amount=order.total,
            order_id=order.id
        )


class PaymentProcessor:
    """
    支付处理器
    负责根据支付方式选择合适的策略并处理支付
    """

    def __init__(self, payment_gateway, transaction_recorder):
        self.payment_gateway = payment_gateway
        self.transaction_recorder = transaction_recorder
        self._strategies: Dict[str, PaymentStrategy] = {}
        self._initialize_strategies()

    def _initialize_strategies(self):
        """初始化所有支付策略"""
        self._strategies['credit_card'] = CreditCardPaymentStrategy(
            self.payment_gateway.card_loader,
            self.transaction_recorder
        )
        self._strategies['paypal'] = PayPalPaymentStrategy(
            self.payment_gateway.paypal_client,
            self.transaction_recorder
        )
        self._strategies['crypto'] = CryptoPaymentStrategy(
            self.payment_gateway.wallet_service,
            self.payment_gateway.transaction_validator,
            self.transaction_recorder
        )

    async def process_payment(self, order, payment_method: str, payment_details: dict) -> PaymentResult:
        """
        处理支付请求

        Args:
            order: 订单对象
            payment_method: 支付方式
            payment_details: 支付详情

        Returns:
            PaymentResult: 支付结果

        Raises:
            PaymentError: 当支付方式不支持或处理失败时抛出
        """
        strategy = self._strategies.get(payment_method)

        if not strategy:
            raise PaymentError(f'Unsupported payment method: {payment_method}')

        context = PaymentContext(strategy)
        return await context.process(order, payment_details)


