```python
# 示例：Python 中使用 AI 辅助诊断数据处理错误
# 运行命令：python data_processor.py

from typing import List, Optional, Dict, Any
from dataclasses import dataclass, field
import json

@dataclass
class ValidationError:
    """验证错误详情"""
    field: str
    message: str
    value: Any

@dataclass
class ProcessingResult:
    """处理结果"""
    success: bool
    data: Optional[List[Dict]] = None
    errors: List[ValidationError] = field(default_factory=list)
    summary: Dict[str, Any] = field(default_factory=dict)

class SmartDataProcessor:
    """
    智能数据处理器
    展示如何使用 AI 辅助进行数据验证和错误处理
    """

    def __init__(self, required_fields: List[str]):
        self.required_fields = required_fields
        self.errors: List[ValidationError] = []

    def validate_item(self, item: Dict[str, Any]) -> bool:
        """
        验证数据项
        AI 辅助：提供详细的验证错误信息
        """
        for field in self.required_fields:
            if field not in item:
                self.errors.append(ValidationError(
                    field=field,
                    message=f"缺少必需字段: {field}",
                    value=None
                ))
                return False

            # 类型检查
            expected_type = self._get_expected_type(field)
            if not isinstance(item[field], expected_type):
                self.errors.append(ValidationError(
                    field=field,
                    message=f"字段 {field} 类型错误，期望 {expected_type.__name__}",
                    value=item[field]
                ))
                return False

        return True

    def _get_expected_type(self, field: str):
        """根据字段名推断期望类型"""
        if 'id' in field.lower():
            return int
        if 'name' in field.lower():
            return str
        if 'count' in field.lower() or 'amount' in field.lower():
            return (int, float)
        return str

    def process_batch(self, items: List[Dict]) -> ProcessingResult:
        """
        批量处理数据
        AI 辅助：收集所有验证错误而非遇到第一个就停止
        """
        valid_items = []

        for idx, item in enumerate(items):
            if self.validate_item(item):
                valid_items.append(self._normalize_item(item))
            else:
                # 记录出错位置
                print(f"数据项 {idx} 验证失败: {items[idx]}")

        return ProcessingResult(
            success=len(valid_items) > 0,
            data=valid_items if valid_items else None,
            errors=self.errors.copy(),
            summary={
                'total': len(items),
                'valid': len(valid_items),
                'invalid': len(self.errors)
            }
        )

    def _normalize_item(self, item: Dict) -> Dict:
        """规范化数据项"""
        return {
            k: v.strip() if isinstance(v, str) else v
            for k, v in item.items()
        }

# 使用示例
if __name__ == '__main__':
    processor = SmartDataProcessor(['id', 'name', 'email'])

    test_data = [
        {'id': 1, 'name': 'Alice', 'email': 'alice@example.com'},
        {'id': '2', 'name': 'Bob', 'email': 'bob@example.com'},  # id 类型错误
        {'name': 'Charlie'},  # 缺少字段
        {'id': 4, 'name': 'Diana', 'email': 'diana@example.com'},
    ]

    result = processor.process_batch(test_data)
    print(f"处理结果: {result.summary}")
    print(f"有效数据: {result.data}")
    print(f"错误数量: {len(result.errors)}")
