// Vue 3 组合式 API - 使用 Cursor AI 生成可复用的数据获取 composable
import { ref, onMounted, computed } from 'vue';

// 通用数据获取 composable
function useFetch<T>(url: string) {
  // 响应式状态
  const data = ref<T | null>(null);
  const loading = ref(false);
  const error = ref<Error | null>(null);

  // 计算属性
  const hasData = computed(() => data.value !== null);
  const isEmpty = computed(() => hasData.value && Array.isArray(data.value) && (data.value as unknown[]).length === 0);

  // 异步获取函数
  const fetchData = async (params?: Record<string, string>) => {
    loading.value = true;
    error.value = null;

    try {
      // 构建完整 URL
      const queryString = params ? '?' + new URLSearchParams(params).toString() : '';
      const fullUrl = url + queryString;

      const response = await fetch(fullUrl, {
        headers: {
          'Content-Type': 'application/json',
          // 添加项目所需的认证头
          'Authorization': `Bearer ${localStorage.getItem('token') || ''}`
        }
      });

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      data.value = await response.json();
    } catch (e) {
      error.value = e instanceof Error ? e : new Error('Unknown error');
      console.error('Fetch error:', error.value);
    } finally {
      loading.value = false;
    }
  };

  // 重新获取数据
  const refresh = () => fetchData();

  return {
    data,
    loading,
    error,
    hasData,
    isEmpty,
    fetchData,
    refresh
  };
}

// 使用示例
// const { data: users, loading, error, refresh } = useFetch<User[]>('/api/users');
