    type: String,
    enum: ['electronics', 'clothing', 'food'],
    required: true
  },
  stock: {
    type: Number,
    default: 0,
    min: 0
  },
  createdAt: {
    type: Date,
    default: Date.now
  }
}, {
  timestamps: true
});

// 创建索引提升查询性能
productSchema.index({ category: 1, price: 1 });

// 实例方法
productSchema.methods.checkAvailability = function(quantity) {
  return this.stock >= quantity;
};


// 静态方法
productSchema.statics.findByCategory = function(category) {
  return this.find({ category }).sort({ createdAt: -1 });
};

const Product = mongoose.model('Product', productSchema);

module.exports = Product;
```



## 常见错误

- 直接使用 AI 生成的代码而不进行安全审查，导致潜在的安全漏洞
- 忽视数据库索引设计，导致查询性能问题
- 缺少统一的错误处理机制，使得错误信息不一致
- 不进行输入验证直接使用 AI 生成的数据处理代码
- 过度依赖 AI 生成的硬编码值，应该使用环境变量
- 没有为 AI 生成的代码编写测试，导致质量不可控
- 忽略异步错误处理，导致潜在的未捕获异常


## 最佳实践

- 在使用 AI 生成代码前先明确需求和项目架构，建立清晰的开发计划
- 对 AI 生成的所有代码进行安全审查，特别是涉及认证授权和数据操作的部分
- 建立团队统一的代码规范和模式库，让 AI 生成的代码保持一致性
- 采用分层架构（Controller-Service-Repository），便于 AI 生成和维护
- 为常用功能创建可复用的模板，减少重复代码生成
- 始终编写单元测试和集成测试，确保 AI 生成代码的正确性
- 使用环境变量管理配置，不要在代码中硬编码敏感信息
- 添加完善的日志记录，便于问题排查和系统监控

